mapper.select:
SELECT * FROM question_bank
WHERE category_level = #{categoryLevel}

    AND subject_name = #{subjectName}


    AND question_type = #{questionType}

ORDER BY RAND()
LIMIT #{limit}

mapper.update:
UPDATE question_bank
SET use_count = use_count + 1
WHERE id = #{id}

mapper.select:
SELECT ar.*, qb.question_title, qb.options, qb.answer_analysis
FROM answer_records ar
LEFT JOIN question_bank qb ON ar.question_id = qb.id
WHERE 1=1

    AND ar.user_id = #{userId}


    AND ar.subject_name = #{subjectName}


    AND ar.question_type = #{questionType}


    AND ar.is_correct = #{isCorrect}


    AND ar.knowledge_point = #{knowledgePoint}


    AND ar.answer_date >= #{startDate}


    AND ar.answer_date <= #{endDate}

ORDER BY ar.answer_date DESC, ar.created_at DESC
LIMIT #{offset}, #{pageSize}
